@namespace Lumeo

@{
    var context = new ContextMenuContext(Open, _x, _y, EventCallback.Factory.Create<bool>(this, SetOpen), EventCallback.Factory.Create<(double, double)>(this, SetPosition));
}

<CascadingValue Value="context" IsFixed="false">
    <div class="relative inline-block" @attributes="AdditionalAttributes">
        @ChildContent
    </div>
</CascadingValue>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public bool Open { get; set; }
    [Parameter] public EventCallback<bool> OpenChanged { get; set; }

    [Obsolete("Use Open instead. IsOpen will be removed in a future release.")]
    [Parameter] public bool IsOpen { get => Open; set => Open = value; }

    [Obsolete("Use OpenChanged instead. IsOpenChanged will be removed in a future release.")]
    [Parameter] public EventCallback<bool> IsOpenChanged { get => OpenChanged; set => OpenChanged = value; }

    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private double _x;
    private double _y;

    private async Task SetOpen(bool value)
    {
        Open = value;
        await OpenChanged.InvokeAsync(value);
    }

    private Task SetPosition((double X, double Y) pos)
    {
        _x = pos.X;
        _y = pos.Y;
        return Task.CompletedTask;
    }

    public record ContextMenuContext(bool IsOpen, double X, double Y, EventCallback<bool> SetOpen, EventCallback<(double, double)> SetPosition);
}

@namespace Lumeo

<button type="button" role="menuitemcheckbox" aria-checked="@EffectiveChecked.ToString().ToLower()" class="@CssClass" @onclick="Toggle" disabled="@Disabled" aria-disabled="@(Disabled ? "true" : null)" @attributes="AdditionalAttributes">
    <span class="flex h-3.5 w-3.5 items-center justify-center">
        @if (EffectiveChecked)
        {
            <SvgGlyph Svg="@(LumeoIcons.Check)" class="h-3.5 w-3.5" />
        }
    </span>
    @ChildContent
</button>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public bool Checked { get; set; }
    [Parameter] public EventCallback<bool> CheckedChanged { get; set; }
    [Parameter] public bool Disabled { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // disabled native attribute also makes the JS menu nav (getMenuItems uses
    // :not([disabled])) skip this item during arrow-key roving.
    private string CssClass => Cx.Merge("relative flex w-full cursor-default select-none items-center gap-2 rounded-sm py-1.5 ps-8 pe-2 text-sm outline-none transition-colors hover:bg-accent hover:text-accent-foreground focus:bg-accent focus:text-accent-foreground disabled:pointer-events-none disabled:opacity-50 disabled:cursor-not-allowed", Class);

    // Uncontrolled checked state lives in a private backing field, NOT in the
    // [Parameter] Checked. Blazor re-applies [Parameter] values from the parent on
    // every render, so self-managing state by writing back into Checked got silently
    // reverted whenever an unrelated parent re-render pushed the original Checked
    // value down. Mirrors the Collapsible controlled/uncontrolled fix (#246).
    private bool _checkedState;
    private bool _initialized;
    private bool _lastCheckedParam;

    /// <summary>
    /// State the component actually renders from. Controlled (CheckedChanged bound):
    /// the parent owns it, so mirror Checked verbatim. Uncontrolled: use our own
    /// backing field so parent re-renders can't clobber the toggle.
    /// </summary>
    private bool EffectiveChecked => CheckedChanged.HasDelegate ? Checked : _checkedState;

    protected override void OnParametersSet()
    {
        // Seed the uncontrolled backing field from Checked on first set (honours an
        // initial Checked="true") and whenever the bound Checked value actually
        // changes (lets callers still drive it imperatively), but never on the no-op
        // re-applications that caused the revert.
        if (!_initialized || Checked != _lastCheckedParam)
        {
            _checkedState = Checked;
            _lastCheckedParam = Checked;
            _initialized = true;
        }
    }

    private async Task Toggle()
    {
        if (Disabled) return;
        var next = !EffectiveChecked;
        // Controlled (Checked bound via CheckedChanged): let the parent own state —
        // fire the callback and render from the parent's next value instead of
        // mutating our own [Parameter], which desyncs if the parent ignores the
        // change. Uncontrolled: self-manage via the backing field. (#246)
        if (CheckedChanged.HasDelegate)
        {
            await CheckedChanged.InvokeAsync(next);
        }
        else
        {
            _checkedState = next;
        }
    }
}

@namespace Lumeo
@implements IAsyncDisposable

@if (Context.IsOpen)
{
    <div id="@_contentId" role="menu" aria-orientation="vertical" class="@CssClass" style="@PositionStyle" @onkeydown="HandleKeyDown" tabindex="-1" @attributes="AdditionalAttributes">
        @ChildContent
    </div>
}

@inject IComponentInteropService Interop

@code {
    [CascadingParameter] public ContextMenu.ContextMenuContext Context { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _contentId = LumeoIds.New("context-menu-content");
    private bool _registered;
    private int _focusedIndex = -1;
    private double _positionedX = double.NaN;
    private double _positionedY = double.NaN;

    private string CssClass => Cx.Merge("fixed z-50 min-w-[8rem] overflow-hidden rounded-md border border-border/40 bg-popover p-1 text-popover-foreground shadow-lg animate-fade-in", Class);

    // Initial inline placement at the raw click point; OnAfterRenderAsync then
    // clamps the menu inside the viewport. The root menu previously rendered
    // partly off-screen near the bottom/right edges (submenus already flip).
    private string PositionStyle => string.Create(System.Globalization.CultureInfo.InvariantCulture, $"position: fixed; left: {Context.X}px; top: {Context.Y}px");

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (Context.IsOpen && !_registered)
        {
            await Interop.RegisterClickOutside(_contentId, null, async () =>
            {
                await Context.SetOpen.InvokeAsync(false);
                await InvokeAsync(StateHasChanged);
            });
            _registered = true;
            _focusedIndex = -1;

            await ClampToViewport();

            // Save where focus was before opening so it returns there on close
            // (WCAG 2.4.3), then move focus to the menu container so Escape/Arrow
            // keys reach the @onkeydown handler. saveFocus installs no Tab trap.
            try { await Interop.SaveFocus(_contentId); } catch (JSDisconnectedException) { }
            try { await Interop.FocusElement(_contentId); } catch (JSDisconnectedException) { }
        }
        else if (Context.IsOpen && _registered && (Context.X != _positionedX || Context.Y != _positionedY))
        {
            // Re-opened at new coordinates (right-click elsewhere while still open).
            await ClampToViewport();
        }
        else if (!Context.IsOpen && _registered)
        {
            await Cleanup();
        }
    }

    private async Task ClampToViewport()
    {
        _positionedX = Context.X;
        _positionedY = Context.Y;
        try { await Interop.PositionAtPoint(_contentId, Context.X, Context.Y); }
        catch (JSDisconnectedException) { }
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        switch (e.Key)
        {
            case "Escape":
                await Context.SetOpen.InvokeAsync(false);
                break;
            case "ArrowDown":
                {
                    var count = await Interop.GetMenuItemCount(_contentId);
                    if (count > 0)
                    {
                        _focusedIndex = (_focusedIndex + 1) % count;
                        await Interop.FocusMenuItemByIndex(_contentId, _focusedIndex);
                    }
                    break;
                }
            case "ArrowUp":
                {
                    var count = await Interop.GetMenuItemCount(_contentId);
                    if (count > 0)
                    {
                        _focusedIndex = _focusedIndex <= 0 ? count - 1 : _focusedIndex - 1;
                        await Interop.FocusMenuItemByIndex(_contentId, _focusedIndex);
                    }
                    break;
                }
            case "Home":
                {
                    var count = await Interop.GetMenuItemCount(_contentId);
                    if (count > 0)
                    {
                        _focusedIndex = 0;
                        await Interop.FocusMenuItemByIndex(_contentId, _focusedIndex);
                    }
                    break;
                }
            case "End":
                {
                    var count = await Interop.GetMenuItemCount(_contentId);
                    if (count > 0)
                    {
                        _focusedIndex = count - 1;
                        await Interop.FocusMenuItemByIndex(_contentId, _focusedIndex);
                    }
                    break;
                }
        }
    }

    private async Task Cleanup()
    {
        try
        {
            await Interop.UnregisterClickOutside(_contentId);
        }
        catch (JSDisconnectedException) { }
        // Return focus to where it was before the menu opened (WCAG 2.4.3).
        try { await Interop.RestoreFocus(_contentId); } catch (JSDisconnectedException) { }
        _registered = false;
        _positionedX = double.NaN;
        _positionedY = double.NaN;
    }

    public async ValueTask DisposeAsync()
    {
        if (_registered) await Cleanup();
    }
}

